from __future__ import annotations

import json
import logging
import os
import struct
import time
from collections.abc import AsyncIterator, Iterator
from contextlib import contextmanager
from typing import Any, Mapping, Protocol
from urllib.parse import urljoin

import httpx

from .errors import (
    APITimeoutError,
    CursorSDKError,
    NetworkError,
    error_from_connect_payload,
)
from .types import JsonObject

CONNECT_PROTOCOL_VERSION = "1"
END_STREAM_FLAG = 0x02

# Streams (Send/ObserveRun/DownloadArtifact) can run for as long as a
# multi-turn task takes, so they need a much longer cap than unary RPCs.
DEFAULT_UNARY_TIMEOUT_SECONDS: float = 60.0
DEFAULT_STREAM_TIMEOUT_SECONDS: float = 600.0

# Sentinel for "caller did not pass this argument", so we can distinguish it
# from the explicit `timeout=None` (which means "no timeout") that
# httpx accepts for disabling timeouts.
_UNSET: Any = object()

# SDK-private logger. Per the standard library convention for libraries
# (PEP 282 / https://docs.python.org/3/howto/logging.html#configuring-logging-for-a-library),
# the SDK never calls `logging.basicConfig(...)` and never touches the root
# logger. The host application owns logging configuration; we attach a
# `NullHandler` so debug calls don't print "No handlers could be found"
# warnings on Python < 3.8, and we set `propagate = False` if (and only if)
# the env-var opt-in path attaches our own stderr handler — without that we
# would leak SDK debug logs into the host's root logger.
_LOG = logging.getLogger("cursor_sdk")
_LOG.addHandler(logging.NullHandler())


def _configure_logging_from_env() -> None:
    """Honor `CURSOR_SDK_LOG=debug|info` by attaching a stderr handler to
    the SDK's own logger only. Never mutates the root logger, so importing
    `cursor_sdk` cannot change the host application's logging setup.
    """
    level = os.environ.get("CURSOR_SDK_LOG", "").lower()
    if level not in {"debug", "info"}:
        return
    handler = logging.StreamHandler()
    handler.setFormatter(
        logging.Formatter("%(asctime)s [%(levelname)s] %(name)s: %(message)s")
    )
    _LOG.addHandler(handler)
    _LOG.propagate = False
    _LOG.setLevel(logging.DEBUG if level == "debug" else logging.INFO)


_configure_logging_from_env()


# Transport-level retries are an idempotency-sensitive policy and must NOT
# be applied uniformly to every unary RPC. Even when a caller opts in to
# `max_retries > 0`, the transport only retries known-idempotent (read-only
# or observation-only) methods. Any RPC with a side effect — Create/Resume
# Agent, Cancel/Archive/Unarchive/Delete Agent, ReloadAgent, CloseAgent,
# Shutdown, and any caller-defined method we don't recognize — is treated
# as non-retryable so a transient 5xx or network blip cannot silently
# replay a destructive operation.
_RETRY_SAFE_METHODS: frozenset[str] = frozenset(
    {
        "Ping",
        "GetVersion",
        "GetAgent",
        "ListAgents",
        "GetRun",
        "ListRuns",
        "WaitLiveRun",
        "GetRunConversation",
        "Me",
        "ListModels",
        "ListRepositories",
        "ListAgentMessages",
        "ListArtifacts",
    }
)


def _is_retry_safe_method(method: str) -> bool:
    """Return True iff the named RPC is safe to retry on transient errors.

    Read-only / observation-only RPCs are safe; mutating RPCs (and any
    method we don't explicitly recognize) are not.
    """
    return method in _RETRY_SAFE_METHODS


class SyncTransport(Protocol):
    """The contract `Client` expects from its transport seam.

    Real implementation: `ConnectTransport`. Tests pass a structural
    fake (a class with these methods) without inheriting from anything,
    which is why this is a `Protocol` rather than an ABC.
    """

    def unary(
        self, service: str, method: str, message: Mapping[str, Any]
    ) -> JsonObject: ...

    def stream(
        self, service: str, method: str, message: Mapping[str, Any]
    ) -> Iterator[JsonObject]: ...

    def close(self) -> None: ...

    def with_options(
        self,
        *,
        timeout: Any = ...,
        unary_timeout: Any = ...,
        stream_timeout: Any = ...,
        max_retries: int | None = ...,
    ) -> "SyncTransport": ...


class AsyncTransport(Protocol):
    """Async mirror of `SyncTransport`. Real impl: `AsyncConnectTransport`."""

    async def unary(
        self, service: str, method: str, message: Mapping[str, Any]
    ) -> JsonObject: ...

    async def stream(
        self, service: str, method: str, message: Mapping[str, Any]
    ) -> AsyncIterator[JsonObject]: ...

    async def aclose(self) -> None: ...

    def with_options(
        self,
        *,
        timeout: Any = ...,
        unary_timeout: Any = ...,
        stream_timeout: Any = ...,
        max_retries: int | None = ...,
    ) -> "AsyncTransport": ...


class DefaultHttpxClient(httpx.Client):
    """`httpx.Client` subclass with the Cursor SDK's defaults.

    Mirrors `openai.DefaultHttpxClient`: callers who want to customize the
    HTTP client (proxies, transports, certs, etc.) can subclass or
    instantiate this directly and still keep the SDK's defaults for
    `timeout` and `follow_redirects`.
    """

    def __init__(self, **kwargs: Any) -> None:
        kwargs.setdefault("timeout", DEFAULT_UNARY_TIMEOUT_SECONDS)
        kwargs.setdefault("follow_redirects", True)
        super().__init__(**kwargs)


def _resolve_timeout(specific: Any, generic: Any, default: Any) -> Any:
    """Resolve one of `unary_timeout` / `stream_timeout` from caller args.

    Order of precedence:
      1. Explicit specific value (incl. ``None`` to disable timeouts).
      2. Legacy ``timeout=`` applied to both phases.
      3. Caller-supplied default.
    Used by both `_TransportBase.__init__` (default = module default) and
    `_TransportBase.with_options` (default = current value).
    """
    if specific is not _UNSET:
        return specific
    if generic is not _UNSET:
        return generic
    return default


class _TransportBase:
    """Shared scaffolding between sync `ConnectTransport` and async
    `AsyncConnectTransport`.

    Owns timeout resolution, header building, and `with_options` view
    construction — the parts that are byte-identical between the two
    transports. Subclasses set `_default_client_class` (sync or async)
    and implement the I/O methods (`unary`, `stream`, `close`/`aclose`).
    """

    _default_client_class: type

    def __init__(
        self,
        base_url: str,
        auth_token: str,
        *,
        timeout: float | None = _UNSET,
        unary_timeout: float | None = _UNSET,
        stream_timeout: float | None = _UNSET,
        max_retries: int | None = 0,
        http_client: Any | None = None,
    ) -> None:
        self.base_url = base_url.rstrip("/") + "/"
        self.auth_token = auth_token
        # Explicit `None` is preserved so callers can disable timeouts the
        # same way `httpx.Client(timeout=None)` does.
        self.unary_timeout = _resolve_timeout(
            unary_timeout, timeout, DEFAULT_UNARY_TIMEOUT_SECONDS
        )
        self.stream_timeout = _resolve_timeout(
            stream_timeout, timeout, DEFAULT_STREAM_TIMEOUT_SECONDS
        )
        self.timeout = self.unary_timeout
        self.max_retries = max(0, int(max_retries or 0))
        if http_client is not None:
            self._client = http_client
            self._owns_client = False
        else:
            self._client = self._default_client_class(timeout=self.unary_timeout)
            self._owns_client = True

    def with_options(
        self,
        *,
        timeout: float | None = _UNSET,
        unary_timeout: float | None = _UNSET,
        stream_timeout: float | None = _UNSET,
        max_retries: int | None = None,
    ) -> "_TransportBase":
        """Return a transport that shares the underlying httpx client but
        overrides the per-call timeout defaults. The returned transport
        does not own the shared client, so closing it does nothing to
        the original.
        """
        cls = type(self)
        new = cls.__new__(cls)
        new.base_url = self.base_url
        new.auth_token = self.auth_token
        new._client = self._client
        new._owns_client = False
        new.unary_timeout = _resolve_timeout(unary_timeout, timeout, self.unary_timeout)
        new.stream_timeout = _resolve_timeout(
            stream_timeout, timeout, self.stream_timeout
        )
        new.timeout = new.unary_timeout
        new.max_retries = (
            self.max_retries if max_retries is None else max(0, int(max_retries))
        )
        return new

    def _headers(self, *, accept: str, content_type: str) -> dict[str, str]:
        return {
            "Accept": accept,
            "Authorization": f"Bearer {self.auth_token}",
            "Connect-Protocol-Version": CONNECT_PROTOCOL_VERSION,
            "Content-Type": content_type,
        }

    @staticmethod
    def _httpx_timeout(timeout: Any) -> Any:
        # `None` disables timeouts in httpx; pass through unchanged. A finite
        # number is applied to all phases (connect/read/write/pool) so it
        # matches the previous `urllib.request.urlopen(timeout=...)` semantic.
        if timeout is None:
            return None
        if isinstance(timeout, httpx.Timeout):
            return timeout
        return httpx.Timeout(timeout)


class ConnectTransport(_TransportBase):
    """Connect JSON transport for unary and server-streaming bridge RPCs.

    Wraps an `httpx.Client`. If `http_client` is supplied, the transport
    uses it as-is and does not close it; otherwise it owns the underlying
    client and `close()` will dispose of it.
    """

    _default_client_class = DefaultHttpxClient

    def close(self) -> None:
        if self._owns_client:
            self._client.close()

    def __enter__(self) -> "ConnectTransport":
        return self

    def __exit__(self, *exc: Any) -> None:
        self.close()

    def unary(
        self, service: str, method: str, message: Mapping[str, Any]
    ) -> JsonObject:
        body = json.dumps(message).encode("utf-8")
        headers = self._headers(
            accept="application/json", content_type="application/json"
        )
        url = urljoin(self.base_url, f"{service}/{method}")
        response = _post_with_retries(
            self._client,
            url,
            body,
            headers,
            self._httpx_timeout(self.unary_timeout),
            max_retries=self.max_retries,
            service=service,
            method=method,
        )
        body_bytes = response.content
        if not body_bytes:
            return {}
        return _json_loads(body_bytes)

    def stream(
        self, service: str, method: str, message: Mapping[str, Any]
    ) -> Iterator[JsonObject]:
        body = encode_stream_envelope(message)
        headers = self._headers(
            accept="application/connect+json",
            content_type="application/connect+json",
        )
        url = urljoin(self.base_url, f"{service}/{method}")
        return _iter_stream(
            self._client,
            url,
            body,
            headers,
            self._httpx_timeout(self.stream_timeout),
        )


def _post_with_retries(
    client: httpx.Client,
    url: str,
    body: bytes,
    headers: Mapping[str, str],
    timeout: Any,
    *,
    max_retries: int,
    service: str,
    method: str,
) -> httpx.Response:
    # Mutating / unknown RPCs collapse to single-attempt regardless of the
    # caller's `max_retries`, so a transport-level retry can never replay a
    # destructive operation (see `_is_retry_safe_method`).
    effective_max_retries = max_retries if _is_retry_safe_method(method) else 0
    for attempt in range(effective_max_retries + 1):
        try:
            _LOG.debug(
                "cursor sdk unary %s/%s attempt=%s", service, method, attempt + 1
            )
            response = client.post(
                url,
                content=body,
                headers=headers,
                timeout=timeout,
            )
        except httpx.RequestError as error:
            if attempt < effective_max_retries:
                _sleep_before_retry(attempt)
                continue
            raise _network_error(error) from error
        if response.status_code < 400:
            return response
        if attempt < effective_max_retries and _is_retryable_status(
            response.status_code
        ):
            _sleep_before_retry(attempt)
            continue
        raise _http_error(response.status_code, response.content, response.headers)
    raise CursorSDKError("Bridge request failed")


def _iter_stream(
    client: httpx.Client,
    url: str,
    body: bytes,
    headers: Mapping[str, str],
    timeout: Any,
) -> Iterator[JsonObject]:
    with _open_stream(client, url, body, headers, timeout) as response:
        if response.status_code >= 400:
            raise _http_error(response.status_code, response.read(), response.headers)
        parser = _ConnectStreamParser(status=response.status_code)
        for chunk in response.iter_raw():
            yield from parser.feed(chunk)
            if parser.ended:
                return
        parser.assert_ended()


class _ConnectStreamParser:
    """Stateful parser for Connect JSON server-stream envelopes.

    Feed raw HTTP body bytes and receive complete envelopes. End-stream
    envelopes set `ended=True`; if they carry an `error` field, `feed()`
    raises a typed `CursorSDKError`. Keeping the framing in one place means
    sync and async transports share the security-sensitive parser exactly.
    """

    def __init__(self, *, status: int | None = None) -> None:
        self._buffer = bytearray()
        self._status = status
        self.ended = False

    def feed(self, chunk: bytes) -> Iterator[JsonObject]:
        self._buffer.extend(chunk)
        while not self.ended and len(self._buffer) >= 5:
            flags = self._buffer[0]
            length = struct.unpack(">I", bytes(self._buffer[1:5]))[0]
            if len(self._buffer) < 5 + length:
                return
            payload = bytes(self._buffer[5 : 5 + length])
            del self._buffer[: 5 + length]
            envelope = _json_loads(payload) if payload else {}
            if flags & END_STREAM_FLAG:
                self.ended = True
                error = envelope.get("error")
                if error:
                    if isinstance(error, Mapping):
                        raise _connect_error(error, status=self._status)
                    raise CursorSDKError(str(error), status=self._status)
                return
            yield envelope

    def assert_ended(self) -> None:
        if not self.ended:
            raise CursorSDKError("Unexpected end of Connect stream")


@contextmanager
def _open_stream(
    client: httpx.Client,
    url: str,
    body: bytes,
    headers: Mapping[str, str],
    timeout: Any,
) -> Iterator[httpx.Response]:
    try:
        with client.stream(
            "POST",
            url,
            content=body,
            headers=headers,
            timeout=timeout,
        ) as response:
            yield response
    except httpx.RequestError as error:
        raise _network_error(error) from error


def _json_loads(body: bytes) -> JsonObject:
    try:
        loaded = json.loads(body.decode("utf-8"))
    except json.JSONDecodeError as error:
        raise CursorSDKError("Bridge returned invalid JSON") from error
    if not isinstance(loaded, dict):
        raise CursorSDKError("Bridge returned a non-object JSON payload")
    return loaded


def _is_retryable_status(status: int) -> bool:
    # 408 (request timeout) and 429 (rate limited) are always safe to retry.
    # 5xx covers transient server-side failures. 409 (conflict) is intentionally
    # excluded because it usually signals a state-mismatch the bridge would
    # rather surface than mask, and unary requests already carry idempotency
    # keys for the cases where retry would actually be safe.
    return status == 408 or status == 429 or status >= 500


def _sleep_before_retry(attempt: int) -> None:
    time.sleep(min(0.25 * (2**attempt), 2.0))


def _http_error(
    status: int,
    body: bytes,
    headers: Mapping[str, str] | None = None,
) -> CursorSDKError:
    if not body:
        return CursorSDKError(
            f"Bridge request failed with HTTP {status}",
            status=status,
            headers=headers,
        )
    try:
        payload = _json_loads(body)
    except CursorSDKError:
        body_text = body.decode("utf-8", errors="replace").strip()
        if len(body_text) > 200:
            body_text = body_text[:200] + "..."
        if body_text:
            return CursorSDKError(
                f"Bridge request failed with HTTP {status}: {body_text}",
                status=status,
                headers=headers,
            )
        return CursorSDKError(
            f"Bridge request failed with HTTP {status}",
            status=status,
            headers=headers,
        )
    error = payload.get("error", payload)
    if isinstance(error, Mapping):
        return _connect_error(error, status=status, headers=headers)
    return CursorSDKError(str(payload), status=status, headers=headers)


def _connect_error(
    error: Mapping[str, Any],
    *,
    status: int | None,
    headers: Mapping[str, str] | None = None,
) -> CursorSDKError:
    parsed = error_from_connect_payload(error, status=status)
    if headers:
        parsed.headers.update(headers)
        retry_after = headers.get("retry-after")
        if retry_after and parsed.retry_after is None:
            parsed.retry_after = retry_after
    return parsed


def _network_error(error: httpx.RequestError) -> CursorSDKError:
    if isinstance(error, httpx.TimeoutException):
        return APITimeoutError(
            f"Bridge request timed out: {error.__class__.__name__}: {error}",
            is_retryable=True,
        )
    return NetworkError(
        f"Bridge request failed: {error.__class__.__name__}: {error}",
        is_retryable=True,
    )


def encode_stream_envelope(payload: Mapping[str, Any], *, end: bool = False) -> bytes:
    """Test helper for constructing Connect JSON stream envelopes."""

    body = json.dumps(payload).encode("utf-8")
    flags = END_STREAM_FLAG if end else 0
    return bytes([flags]) + struct.pack(">I", len(body)) + body


def _bridge_shutdown_request(
    base_url: str, auth_token: str, *, grace_seconds: int
) -> tuple[str, bytes, dict[str, str]]:
    """Build the URL/body/headers for a bridge Shutdown control RPC.

    Factored out so the sync and async shutdown helpers agree on the
    wire shape without importing each other.
    """
    url = base_url.rstrip("/") + "/sdk.v1.SdkBridgeControlService/Shutdown"
    body = json.dumps({"graceSeconds": grace_seconds}).encode("utf-8")
    headers = {
        "Accept": "application/json",
        "Authorization": f"Bearer {auth_token}",
        "Connect-Protocol-Version": CONNECT_PROTOCOL_VERSION,
        "Content-Type": "application/json",
    }
    return url, body, headers


def post_bridge_shutdown(
    base_url: str, auth_token: str, *, grace_seconds: int = 0
) -> None:
    """Send a Shutdown control RPC to the bridge without going through `Client`.

    Used by `Bridge.close` to break the `_bridge -> _client -> _bridge`
    import cycle: bridges only need to issue this single RPC, so the full
    `Client` machinery is overkill and forces a function-local import to
    avoid the cycle. Best-effort: any transport error is swallowed so the
    caller can always proceed to terminate the subprocess.
    """
    url, body, headers = _bridge_shutdown_request(
        base_url, auth_token, grace_seconds=grace_seconds
    )
    try:
        with DefaultHttpxClient(timeout=DEFAULT_UNARY_TIMEOUT_SECONDS) as client:
            client.post(url, content=body, headers=headers)
    except httpx.RequestError:
        pass
